// src/audio_automation.rs
//
// The Audio Automation module dynamically adjusts the audio environment
// based on regional invariants (from the Spectral Library) and current
// entertainment metrics. It manages ambient soundscapes, event-triggered
// audio cues, and ensures that the sonic landscape reinforces the
// procedural implication and atmosphere defined by the selected style
// and regional context.

use crate::spectral_library::{HorrorInvariants, RegionId};
use std::collections::HashMap;

// --- Configuration for Audio Generation ---

#[derive(Debug, Clone)]
pub struct AudioConfig {
    pub base_ambience_volume: f64,
    pub catastrophe_weight: f64,    // Influenced by CIC
    pub mythic_weight: f64,         // Influenced by MDI
    pub archival_uncertainty: f64,  // Influenced by AOS
    pub spectral_activity: f64,     // Influenced by SPR
    pub coherence_hint: f64,        // Influ, HVF
}

impl AudioConfig {
    /// Derives an AudioConfig from regional HorrorInvariants.
    /// This is a simplified example; a real implementation would be more nuanced.
    pub fn from_invariants(invariants: &HorrorInvariants) -> Self {
        let mut catastrophe_weight = 0.1;
        let mut mythic_weight = 0.05;
        let mut archival_uncertainty = 0.05;
        let mut spectral_activity = 0.1;
        let mut coherence_hint = 0.5;

        // Example mappings from invariants to audio parameters
        // CIC (Catastrophic Imprint Coefficient) -> Higher CIC increases ambient unease, low-frequency drones
        catastrophe_weight += invariants.CIC * 0.2;

        // MDI (Mythic Density Index) -> Higher MDI increases frequency of folklore-inspired sounds (whispers, distant music)
        mythic_weight += invariants.MDI * 0.15;

        // AOS (Archival Opacity Score) -> Higher AOS increases audio artifacts, static, indistinct murmurs
        archival_uncertainty += invariants.AOS * 0.1;

        // SPR (Spectral Plausibility Rating) -> Higher SPR increases likelihood of spectral audio cues (footsteps, voices)
        spectral_activity += invariants.SPR * 0.15;

        // SHCI (Spectral-Historical Coherence Index) -> Higher SHCI makes audio cues align better with historical context
        coherence_hint += invariants.SHCI * 0.1;

        // Clamp factors to reasonable ranges
        catastrophe_weight = catastrophe_weight.clamp(0.0, 1.0);
        mythic_weight = mythic_weight.clamp(0.0, 1.0);
        archival_uncertainty = archival_uncertainty.clamp(0.0, 1.0);
        spectral_activity = spectral_activity.clamp(0.0, 1.0);
        coherence_hint = coherence_hint.clamp(0.0, 1.0);

        AudioConfig {
            base_ambience_volume: 0.3, // Base level, adjusted by factors
            catastrophe_weight,
            mythic_weight,
            archival_uncertainty,
            spectral_activity,
            coherence_hint,
        }
    }
}

// --- Audio Asset Categories ---

#[derive(Debug, Clone, PartialEq, Eq, Hash)]
pub enum AudioCategory {
    AmbientBase,
    CatastropheDrone,
    Folk    ArchivalStatic,
    SpectralPresence,
    HistoricalEcho,
    // ... other categories
}

#[derive(Debug, Clone)]
pub struct AudioAsset {
    pub name: String,
    pub category: AudioCategory,
    pub base_volume: f64,
    pub pitch_variance: f64,
    pub min_distance: Option<f32>, // For 3D audio
    pub max_distance: Option<f32>, // For 3D audio
    pub tags: Vec<String>, // e.g., ["soviet", "industrial", "desert"], for style-specific filtering
}

// --- Main Audio Automation Module ---

pub struct AudioAutomation {
    config: AudioConfig,
    assets: HashMap<AudioCategory, Vec<AudioAsset>>, // Pool of assets per category
    active_channels: HashMap<AudioCategory, ActiveChannel>,
    rng_state: u64, // Simple state for a custom RNG
}

#[derive(Debug, Clone)]
struct ActiveChannel {
    current_asset: Option<AudioAsset>,
    cooldown: f64, // Time until next event in this channel
    volume: f64,
    playing: bool,
}

impl AudioAutomation {
    /// Creates a new AudioAutomation instance from a configuration and a pool of assets.
    pub fn new(config: AudioConfig, asset_pool: HashMap<AudioCategory, Vec<AudioAsset>>) -> Self {
        let mut active_channels = HashMap::new();
        for category in asset_pool.keys() {
             active_channels.insert(category.clone(), ActiveChannel {
                 current_asset: None,
                 cooldown: 0.0,
                 volume: 0.0,
                 playing: false,
             });
         }

        AudioAutomation {
            config,
            assets: asset_pool,
            active_channels,
            rng_state: 12345, // Initialize RNG state
        }
    }

    /// Updates the audio environment based on elapsed time and current state.
    /// This function would typically be called once per frame or audio tick.
    pub fn update(&mut self, dt: f64) {
        // Update cooldowns
        for channel in self.active_channels.values_mut() {
            if channel.cooldown > 0.0 {
                channel.cooldown -= dt;
            }
        }

        // Example: Trigger ambient base sound if not playing and cooldown is over
        if let Some(base_channel) = self.active_channels.get_mut(&AudioCategory::AmbientBase) {
            if !base_channel.playing && base_channel.cooldown <= 0.0 {
                if let Some(asset) = self.select_asset(&AudioCategory::AmbientBase) {
                    base_channel.current_asset = Some(asset);
                    base_channel.volume = self.config.base_ambience_volume;
                    base_channel.playing = true;
                    base_channel.cooldown = self.calculate_cooldown(&AudioCategory::AmbientBase); // Placeholder
                }
            }
        }

        // Example: Trigger catastrophe drone based on CIC weight
        if self.next_random() < self.config.catastrophe_weight {
            self.trigger_category_if_ready(AudioCategory::CatastropheDrone);
        }
        // Example: Trigger folklore whisper based on MDI weight
        if self.next_random() < self.config.mythic_weight {
            self.trigger_category_if_ready(AudioCategory::FolkloreWhisper);
        }
        // Example: Trigger archival static based on AOS weight
        if self.next_random() < self.config.archival_uncertainty {
            self.trigger_category_if_ready(AudioCategory::ArchivalStatic);
        }
        // Example: Trigger spectral presence based on SPR weight
        if self.next_random() < self.config.spectral_activity {
            self.trigger_category_if_ready(AudioCategory::SpectralPresence);
        }
        // Example: Trigger historical echo based on SHCI weight and coherence
        if self.next_random() < self.config.spectral_activity * self.config.coherence_hint { // Combining SPR and SHCI influence
            self.trigger_category_if_ready(AudioCategory::HistoricalEcho);
        }
    }

    // --- Helper Methods ---

    fn next_random(&mut self) -> f64 {
        // Simple Linear Congruential Generator (LCG) for demonstration.
        self.rng_state = self.rng_state.wrapping_mul(1664525).wrapping_add(1013904223);
        (self.rng_state as f64) / (u64::MAX as f64)
    }

    fn select_asset(&mut self, category: &AudioCategory) -> Option<AudioAsset> {
        // Select an asset from the pool for the given category.
        // This could be random, round-robin, or based on more complex logic.
        if let Some(pool) = self.assets.get(category) {
            if !pool.is_empty() {
                let index = (self.next_random() * pool.len() as f64) as usize;
                return Some(pool[index].clone()); // Return a clone of the selected asset
            }
        }
        None
    }

    fn trigger_category_if_ready(&mut self, category: AudioCategory) {
        if let Some(channel) = self.active_channels.get_mut(&category) {
            if !channel.playing && channel.cooldown <= 0.0 {
                if let Some(asset) = self.select_asset(&category) {
                    channel.current_asset = Some(asset);
                    // Calculate volume based on config weight and asset base volume
                    let weight = match category {
                        AudioCategory::CatastropheDrone => self.config.catastrophe_weight,
                        AudioCategory::FolkloreWhisper => self.config.mythic_weight,
                        AudioCategory::ArchivalStatic => self.config.archival_uncertainty,
                        AudioCategory::SpectralPresence => self.config.spectral_activity,
                        AudioCategory::HistoricalEcho => self.config.coherence_hint, // Or combined weight
                        _ => 0.1, // Default
                    };
                    channel.volume = asset.base_volume * weight;
                    channel.playing = true;
                    channel.cooldown = self.calculate_cooldown(&category); // Placeholder
                    // In a real engine, this would send the asset to the audio playback system
                    println!("Triggering audio: {} (Category: {:?}, Volume: {:.2})", channel.current_asset.as_ref().unwrap().name, category, channel.volume);
                }
            }
        }
    }

    fn calculate_cooldown(&self, _category: &AudioCategory) -> f64 {
        // Placeholder for cooldown calculation based on category, RNG, or other factors
        5.0 + self.next_random() * 10.0 // Random cooldown between 5 and 15 seconds
    }
}

